const data = $input.first().json;
const products = data.products || [];
const types = data.types || [];

if (products.length === 0) {
  return [{ json: { skip: true, total: data.total, message: 'Нет продуктов для классификации' } }];
}

const productList = products.map(p => `ID:${p.id} | ${p.name} | группа: ${p.group || 'нет'}`).join('\n');

const prompt = `Ты классификатор изделий мебельной фабрики. Вот доступные типы изделий: ${types.join(', ')}.

ВАЖНО: Классифицируй ТОЛЬКО готовые изделия (диван, стул, кресло, кровать и т.д.).
НЕ классифицируй составные части и комплектующие: ножки, спинки, сидушки, подлокотники, подушки сидений, мягкие элементы, царги, опоры, механизмы, фурнитуру, чехлы отдельные.
Если продукт — это составная часть, ставь тип "null".
Если не можешь определить тип — тоже ставь "null".

Верни ТОЛЬКО JSON массив без markdown: [{"id":число,"type":"название типа или null"}]

Продукты:
${productList}`;

return [{ json: { prompt, products, types, total: data.total, skip: false } }];

const raw = $input.first().json.choices[0].message.content;
let text = raw.trim();
if (text.startsWith('```')) {
  text = text.split('\n').slice(1).join('\n').replace(/```$/, '').trim();
}

let assignments = [];
try {
  const parsed = JSON.parse(text);
  if (Array.isArray(parsed)) {
    assignments = parsed
      .filter(a => a.type && a.type !== 'null' && a.type !== null)
      .map(a => ({ product_id: a.id, type_name: a.type }));
  }
} catch(e) {
  const match = text.match(/\[[\s\S]*\]/);
  if (match) {
    try {
      const parsed2 = JSON.parse(match[0]);
      assignments = parsed2
        .filter(a => a.type && a.type !== 'null' && a.type !== null)
        .map(a => ({ product_id: a.id, type_name: a.type }));
    } catch(e2) {}
  }
}

const prevData = $('Build Prompt').first().json;
return [{ json: { assignments, total: prevData.total, classified: assignments.length, products_count: prevData.products.length } }];

const saveResult = $input.first().json;
const prevData = $('Parse Result').first().json;

return [{ json: {
  response: `Обработано ${prevData.products_count} продуктов. Классифицировано: ${saveResult.updated}. Пропущено: ${saveResult.skipped}. Осталось без типа: ${prevData.total - saveResult.updated}.`,
  updated: saveResult.updated,
  skipped: saveResult.skipped,
  remaining: prevData.total - saveResult.updated
} }];
